create table dirkspzm32.sec_action_info (
    action_id           number(*, 0) not null enable,
    section_id          number(*, 0) not null enable,
    name                varchar2(255 char) not null enable,
    caption             varchar2(255 char),
    description         varchar2(255 char),
    help_file           varchar2(255 char),
    mod_id              number(*, 0),
    category            varchar2(255 char),
    lang_cn_caption     varchar2(255 char),
    lang_cn_description varchar2(255 char),
    created_date        date
);

alter table dirkspzm32.sec_action_info
    add constraint pk_sec_action_info primary key ( action_id )
        using index enable;

alter table dirkspzm32.sec_action_info
    add constraint uix_action_section unique ( section_id,
                                               name )
        using index enable;


